parameters.jsCode:
const claudeResp = $input.first().json;
const scriptText = claudeResp.content[0].text.trim();

let script;
try {
  const jsonMatch = scriptText.match(/\{[\s\S]*\}/);
  script = JSON.parse(jsonMatch ? jsonMatch[0] : scriptText);
} catch(e) {
  throw new Error('Error parsing script: ' + e.message);
}

// Determinar el avatar_id según la plataforma
const platform = $('Webhook Entrada').item.json.body.platform;
const isShortForm = platform === 'tiktok';

return [{
  json: {
    content_id: $('Webhook Entrada').item.json.body.content_id,
    topic: $('Webhook Entrada').item.json.body.topic,
    platform: platform,
    platforms: [platform],
    scheduled_date: $('Webhook Entrada').item.json.body.scheduled_date,
    scheduled_time: $('Webhook Entrada').item.json.body.scheduled_time,
    script: script,
    heygen_text: script.heygen_input_text,
    on_screen_text: script.on_screen_text,
    // Configuración HeyGen
    avatar_id: 'Sara_Bookfast_v1',
    voice_id: 'es-ES-ElviraNeural',
    background: isShortForm ? 'bg-salon-modern' : 'bg-office-blue',
    dimension: isShortForm 
      ? { width: 1080, height: 1920 }  // TikTok/Reels 9:16
      : { width: 1920, height: 1080 }  // YouTube/Facebook 16:9
  }
}];

const heygenResp = $input.first().json;
const videoId = heygenResp.data?.video_id || heygenResp.video_id;

if (!videoId) {
  throw new Error('HeyGen no devolvió video_id: ' + JSON.stringify(heygenResp));
}

return [{
  json: {
    ...$('Parsear Script').item.json,
    heygen_video_id: videoId,
    heygen_status: 'processing',
    polling_attempts: 0,
    max_polling_attempts: 30  // 30 intentos × 30s = 15 minutos máx
  }
}];

const statusResp = $input.first().json;
const status = statusResp.data?.status || statusResp.status;
const videoUrl = statusResp.data?.video_url || statusResp.video_url;
const prevData = $('Guardar Video ID').item.json;

return [{
  json: {
    ...prevData,
    heygen_status: status,
    video_url: videoUrl || null,
    polling_attempts: (prevData.polling_attempts || 0) + 1,
    is_complete: status === 'completed',
    is_failed: status === 'failed',
    should_retry: status !== 'completed' && status !== 'failed' && (prevData.polling_attempts || 0) < prevData.max_polling_attempts
  }
}];

