const copyResp = $input.first().json;
const copyText = copyResp.content[0].text.trim();

let copy;
try {
  const jsonMatch = copyText.match(/\{[\s\S]*\}/);
  copy = JSON.parse(jsonMatch ? jsonMatch[0] : copyText);
} catch(e) {
  copy = {};
}

const videoData = $('Evaluar Status').item.json;

return [{
  json: {
    content_id: videoData.content_id,
    video_url: videoData.video_url,
    platforms: videoData.platforms,
    scheduled_date: videoData.scheduled_date,
    scheduled_time: videoData.scheduled_time,
    content_type: 'video',
    copy: copy,
    on_screen_text: videoData.on_screen_text,
    ready_to_publish: true
  }
}];
